SELECT AVG(bulk_oil) AS average_bulk_oil
FROM reservoir_data
WHERE method_id = 0;

SELECT zone_id, zone_name
FROM reservoir_zones
ORDER BY created_at DESC;

SELECT zone_id
FROM reservoir_data
WHERE bulk_oil > 1000;

SELECT zone_name
FROM reservoir_zones
WHERE zone_id = 0;

SELECT DISTINCT zone_name
FROM reservoir_zones
ORDER BY zone_name;

SELECT data_id, MAX(version) AS max_version
FROM reservoir_data
GROUP BY data_id;

SELECT bulk_oil
FROM reservoir_data
WHERE version = (SELECT MAX(version) FROM reservoir_data);
